scwin.f_Create = function () {
  scwin.ModeState = "insOnLoad";
  ds_fmsInterface.insertRow(ds_fmsInterface.getRowCount());
  $c.gus.cfEnableKeyData($p);
  ds_fmsInterface.setCellData(ds_fmsInterface.getRowCount() - 1, "osideClsCd", "F");
  gr_fmsInterface.setReadOnly("grid", true);
};
scwin.f_Save = async function () {
  let selpchClsCd = "";
  if (ds_fmsInterface.getUpdatedIndex().length == 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  for (let row = 0; row < ds_fmsInterface.getRowCount(); row++) {
    let rowStatus = ds_fmsInterface.getRowStatus(row);
    if (rowStatus == "C" || rowStatus == "U") {
      selpchClsCd = ds_fmsInterface.getCellData(row, "selpchClsCd");
      if (selpchClsCd == "1") {
        ds_fmsInterface.setCellData(row, "slipKndCd", "H24");
        ds_fmsInterface.setCellData(row, "acctCd", "");
      } else if (selpchClsCd == "2") {
        ds_fmsInterface.setCellData(row, "slipKndCd", "H25");
        ds_fmsInterface.setCellData(row, "acctCd", "");
      }
    }
  }
  let chkValid = await $c.gus.cfValidate($p, [gr_fmsInterface]);
  if (chkValid) {
    let chk = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (chk == true) {
      await $c.sbm.execute($p, sbm_slipKnd);
    }
  }
};
