scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  let rtnList = new Array();
  let pWhere;
  switch (disGubun) {
    case 1:
      rtnList = $c.gus.cfCommonPopUp($p, "retrieveClntEmpNoList", pCode, pName, "T", null, null, null, null, null, null, null, null, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_clntNoCond, txt_clntNmCond);
      break;
    case 2:
      rtnList = $c.gus.cfCommonPopUp($p, "retrieveClntEmpNoList", pCode, "", "T", null, null, null, null, null, null, null, null, null);
      if (rtnList != null && rtnList[0] != "N/A") {
        let curRow = ds_fmsInterface.getRowPosition();
        ds_fmsInterface.setCellData(curRow, "clntNo", rtnList[0]);
        ds_fmsInterface.setCellData(curRow, "clntNm", rtnList[1]);
      }
      break;
    case 3:
      rtnList = $c.gus.cfCommonPopUp($p, "retrieveAcctDeptCdInfo", pCode, "", "T", null, null, null, null, null, null, null, null, null);
      if (rtnList != null && rtnList[0] != "N/A") {
        let curRow = ds_fmsInterface.getRowPosition();
        ds_fmsInterface.setCellData(curRow, "acctDeptCd", rtnList[0]);
        ds_fmsInterface.setCellData(curRow, "acctDeptNm", rtnList[1]);
      }
      break;
    case 4:
      rtnList = $c.gus.cfCommonPopUp($p, "retrieveClntEmpNoList", pCode, pName, "T", null, null, null, null, null, null, null, null, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_clntNo2, txt_clntNm2);
      break;
  }
  return;
};
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }
  $c.gus.cfClearPairObj($p, pairObj);
  let pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
  } else {
    scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
  }
};
