scwin.f_DelRow = async function () {
  if (ds_fmsInterface.getRowCount() == 0) {
    await $c.win.alert($p, "삭제할 데이타가 없습니다");
    return;
  }
  let curRow = ds_fmsInterface.getRowPosition();
  let slipNo = ds_fmsInterface.getCellData(curRow, "slipNo");
  if (slipNo != "") {
    await $c.win.alert($p, curRow + 1 + "행은 이미 전표를 생성하였으므로 삭제하실 수 없습니다.");
    return;
  }
  ds_fmsInterface.removeRow(curRow);
};
scwin.f_DelRowAll = async function () {
  if (ds_fmsInterface.getRowCount() == 0) {
    await $c.win.alert($p, "삭제할 데이타가 없습니다");
    return;
  }
  let slipNo = "";
  for (let x = 0; x < ds_fmsInterface.getRowCount(); x++) {
    slipNo = ds_fmsInterface.getCellData(x, "slipNo");
    if (slipNo != "") {
      await $c.win.alert($p, x + 1 + "행은 이미 전표를 생성하였으므로 삭제하실 수 없습니다.");
      return;
    }
    ds_fmsInterface.removeRow(x);
  }
};
