scwin.f_certiPrint = async function () {
  $c.gus.OZStartBatch($p);
  let tnxMmVal = ed_tnxMm.getValue();
  let ctrlNo = ed_clntNo2.getValue();
  let constSiteVal = lc_constSite.getValue();
  let curDt = ed_tnxMm.getValue().substring(4, 6);
  let chkValid = await $c.gus.cfValidate($p, [ed_tnxMm, ed_clntNo2, lc_constSite]);
  if (!chkValid) {
    return;
  }
  if (constSiteVal.trim() == "") {
    await $c.win.alert($p, "공사현장은 필수 입력항목입니다.");
    lc_constSite.setFocus();
    return;
  }
  let odiParam = new $c.gus.ODIParam("eq_630_01_04b");
  odiParam.add("tnxMm", tnxMmVal);
  odiParam.add("ctrlNo", ctrlNo);
  odiParam.add("constSite", constSiteVal);
  odiParam.add("curDt", curDt);
  let formParam = new $c.gus.FormParam();
  let viewerParam = new $c.gus.ViewerParam();
  viewerParam.add("viewer.zoom", "100");
  viewerParam.add("print.mode", "silent");
  viewerParam.add("print.copies", 1);
  viewerParam.add("viewer.useprogressbar", "false");
  $c.gus.cfOZReport($p, "chb_printCheck", "chb_previewCheck", "/ps/eq/fmsmgnt/eq_630_01_04b.ozr", odiParam, viewerParam, formParam);
  $c.gus.OZExecuteBatch($p);
};
